"""Unit tests for Coder Failure Handler Langfuse prompt fetch."""

from __future__ import annotations

import pytest

from agents.coder_failure_handler.constants import (
    BUG_REPORT_PROMPT_NAME,
    LEADER_PROMPT_NAME,
)
from agents.coder_failure_handler.langfuse_prompts import (
    fetch_coder_failure_handler_instructions,
)


class _FakePrompt:
    def __init__(self, text: str) -> None:
        self.prompt = text


class _FakeClient:
    def __init__(self, mapping: dict[str, str]) -> None:
        self._mapping = mapping

    def get_prompt(
        self,
        name: str,
        *,
        label: str,
        cache_ttl_seconds: int | None = None,
    ) -> object:
        if label != "production":
            raise KeyError(label)
        return _FakePrompt(self._mapping[name])


_BUG_REPORT_BODY = "File a bug: title, summary, run details."
_LEADER_BODY = "You are the leader. Template: {{bug_report_template}}"


def test_fetch_assembles_instructions(monkeypatch: pytest.MonkeyPatch) -> None:
    monkeypatch.setenv("LANGFUSE_PROMPT_LABEL", "production")
    client = _FakeClient(
        {
            LEADER_PROMPT_NAME: _LEADER_BODY,
            BUG_REPORT_PROMPT_NAME: _BUG_REPORT_BODY,
        }
    )

    result = fetch_coder_failure_handler_instructions(client)

    assert "You are the leader." in result
    assert _BUG_REPORT_BODY in result
    assert "{{bug_report_template}}" not in result


def test_fetch_propagates_empty_leader_body(monkeypatch: pytest.MonkeyPatch) -> None:
    monkeypatch.setenv("LANGFUSE_PROMPT_LABEL", "production")
    client = _FakeClient(
        {
            LEADER_PROMPT_NAME: "",
            BUG_REPORT_PROMPT_NAME: _BUG_REPORT_BODY,
        }
    )

    with pytest.raises(ValueError, match="has no usable text body"):
        fetch_coder_failure_handler_instructions(client)


def test_fetch_propagates_empty_bug_report_body(monkeypatch: pytest.MonkeyPatch) -> None:
    monkeypatch.setenv("LANGFUSE_PROMPT_LABEL", "production")
    client = _FakeClient(
        {
            LEADER_PROMPT_NAME: _LEADER_BODY,
            BUG_REPORT_PROMPT_NAME: "",
        }
    )

    with pytest.raises(ValueError, match="has no usable text body"):
        fetch_coder_failure_handler_instructions(client)

